// Test stackalloc with Span<nint> and Span<nuint>
#:property AllowUnsafeBlocks=true

Console.WriteLine($"IntPtr.Size = {IntPtr.Size} bytes ({"64-bit" ?? "32-bit"})");

// stackalloc Span<nint>
Span<nint> signedSpan = stackalloc nint[5];
for (int i = 0; i < signedSpan.Length; i++)
    signedSpan[i] = i * 10;

Console.WriteLine("\nSpan<nint> via stackalloc:");
for (int i = 0; i < signedSpan.Length; i++)
    Console.WriteLine($"  signedSpan[{i}] = {signedSpan[i]}");

// stackalloc Span<nuint>
Span<nuint> unsignedSpan = stackalloc nuint[5];
for (int i = 0; i < unsignedSpan.Length; i++)
    unsignedSpan[i] = (nuint)(i * 100);

Console.WriteLine("\nSpan<nuint> via stackalloc:");
for (int i = 0; i < unsignedSpan.Length; i++)
    Console.WriteLine($"  unsignedSpan[{i}] = {unsignedSpan[i]}");

Console.WriteLine("\n✅ stackalloc with Span<nint> and Span<nuint> works!");

